67: func (s *Storage) Create(ctx context.Context, obj runtime.Object, createValidation rest.ValidateObjectFunc, options *metav1.CreateOptions) (runtime.Object, error) {
68: 	if rbacregistry.EscalationAllowed(ctx) || rbacregistry.RoleEscalationAuthorized(ctx, s.authorizer) {
69: 		return s.StandardStorage.Create(ctx, obj, createValidation, options)
70: 	}
71: 
72: 	role := obj.(*rbac.Role)
73: 	rules := role.Rules
74: 	if err := rbacregistryvalidation.ConfirmNoEscalationInternal(ctx, s.ruleResolver, rules); err != nil {
75: 		return nil, errors.NewForbidden(groupResource, role.Name, err)
76: 	}
77: 	return s.StandardStorage.Create(ctx, obj, createValidation, options)
