25: // Covers determines whether or not the ownerRules cover the servantRules in terms of allowed actions.
26: // It returns whether or not the ownerRules cover and a list of the rules that the ownerRules do not cover.
27: func Covers(ownerRules, servantRules []rbacv1.PolicyRule) (bool, []rbacv1.PolicyRule) {
28: 	// 1.  Break every servantRule into individual rule tuples: group, verb, resource, resourceName
29: 	// 2.  Compare the mini-rules against each owner rule.  Because the breakdown is down to the most atomic level, we're guaranteed that each mini-servant rule will be either fully covered or not covered by a single owner rule
30: 	// 3.  Any left over mini-rules means that we are not covered and we have a nice list of them.
31: 	// TODO: it might be nice to collapse the list down into something more human readable
32: 
33: 	subrules := []rbacv1.PolicyRule{}
34: 	for _, servantRule := range servantRules {
35: 		subrules = append(subrules, BreakdownRule(servantRule)...)
36: 	}
37: 
38: 	uncoveredRules := []rbacv1.PolicyRule{}
39: 	for _, subrule := range subrules {
40: 		covered := false
41: 		for _, ownerRule := range ownerRules {
42: 			if ruleCovers(ownerRule, subrule) {
43: 				covered = true
44: 				break
45: 			}
46: 		}
47: 
48: 		if !covered {
49: 			uncoveredRules = append(uncoveredRules, subrule)
50: 		}
51: 	}
52: 
53: 	return (len(uncoveredRules) == 0), uncoveredRules
54: }
55: 
56: // BreadownRule takes a rule and builds an equivalent list of rules that each have at most one verb, one
57: // resource, and one resource name
58: func BreakdownRule(rule rbacv1.PolicyRule) []rbacv1.PolicyRule {
59: 	subrules := []rbacv1.PolicyRule{}
60: 	for _, group := range rule.APIGroups {
61: 		for _, resource := range rule.Resources {
62: 			for _, verb := range rule.Verbs {
63: 				if len(rule.ResourceNames) > 0 {
64: 					for _, resourceName := range rule.ResourceNames {
65: 						subrules = append(subrules, rbacv1.PolicyRule{APIGroups: []string{group}, Resources: []string{resource}, Verbs: []string{verb}, ResourceNames: []string{resourceName}})
66: 					}
67: 
68: 				} else {
69: 					subrules = append(subrules, rbacv1.PolicyRule{APIGroups: []string{group}, Resources: []string{resource}, Verbs: []string{verb}})
70: 				}
71: 
72: 			}
73: 		}
74: 	}
75: 
76: 	// Non-resource URLs are unique because they only combine with verbs.
77: 	for _, nonResourceURL := range rule.NonResourceURLs {
78: 		for _, verb := range rule.Verbs {
79: 			subrules = append(subrules, rbacv1.PolicyRule{NonResourceURLs: []string{nonResourceURL}, Verbs: []string{verb}})
80: 		}
81: 	}
82: 
83: 	return subrules
84: }
85: 
86: func has(set []string, ele string) bool {
87: 	for _, s := range set {
88: 		if s == ele {
89: 			return true
90: 		}
91: 	}
92: 	return false
93: }
94: 
95: func hasAll(set, contains []string) bool {
96: 	owning := make(map[string]struct{}, len(set))
97: 	for _, ele := range set {
98: 		owning[ele] = struct{}{}
99: 	}
100: 	for _, ele := range contains {
101: 		if _, ok := owning[ele]; !ok {
102: 			return false
103: 		}
104: 	}
105: 	return true
106: }
107: 
108: func resourceCoversAll(setResources, coversResources []string) bool {
109: 	// if we have a star or an exact match on all resources, then we match
110: 	if has(setResources, rbacv1.ResourceAll) || hasAll(setResources, coversResources) {
111: 		return true
112: 	}
113: 
114: 	for _, path := range coversResources {
115: 		// if we have an exact match, then we match.
116: 		if has(setResources, path) {
117: 			continue
118: 		}
119: 		// if we're not a subresource, then we definitely don't match.  fail.
120: 		if !strings.Contains(path, "/") {
121: 			return false
122: 		}
123: 		tokens := strings.SplitN(path, "/", 2)
124: 		resourceToCheck := "*/" + tokens[1]
125: 		if !has(setResources, resourceToCheck) {
126: 			return false
127: 		}
128: 	}
129: 
130: 	return true
131: }
132: 
133: func nonResourceURLsCoversAll(set, covers []string) bool {
134: 	for _, path := range covers {
135: 		covered := false
136: 		for _, owner := range set {
137: 			if nonResourceURLCovers(owner, path) {
138: 				covered = true
139: 				break
140: 			}
141: 		}
142: 		if !covered {
143: 			return false
144: 		}
145: 	}
146: 	return true
147: }
148: 
149: func nonResourceURLCovers(ownerPath, subPath string) bool {
150: 	if ownerPath == subPath {
151: 		return true
152: 	}
153: 	return strings.HasSuffix(ownerPath, "*") && strings.HasPrefix(subPath, strings.TrimRight(ownerPath, "*"))
154: }
155: 
156: // ruleCovers determines whether the ownerRule (which may have multiple verbs, resources, and resourceNames) covers
157: // the subrule (which may only contain at most one verb, resource, and resourceName)
158: func ruleCovers(ownerRule, subRule rbacv1.PolicyRule) bool {
159: 	verbMatches := has(ownerRule.Verbs, rbacv1.VerbAll) || hasAll(ownerRule.Verbs, subRule.Verbs)
160: 	groupMatches := has(ownerRule.APIGroups, rbacv1.APIGroupAll) || hasAll(ownerRule.APIGroups, subRule.APIGroups)
161: 	resourceMatches := resourceCoversAll(ownerRule.Resources, subRule.Resources)
162: 	nonResourceURLMatches := nonResourceURLsCoversAll(ownerRule.NonResourceURLs, subRule.NonResourceURLs)
163: 
164: 	resourceNameMatches := false
165: 
166: 	if len(subRule.ResourceNames) == 0 {
167: 		resourceNameMatches = (len(ownerRule.ResourceNames) == 0)
168: 	} else {
169: 		resourceNameMatches = (len(ownerRule.ResourceNames) == 0) || hasAll(ownerRule.ResourceNames, subRule.ResourceNames)
170: 	}
171: 
172: 	return verbMatches && groupMatches && resourceMatches && resourceNameMatches && nonResourceURLMatches
173: }
